import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

const Checkout = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const orderData = location.state || {};
  
  const [paymentData, setPaymentData] = useState({
    cardNumber: '',
    expiryDate: '',
    cvv: '',
    cardName: '',
    saveCard: false
  });

  const [isProcessing, setIsProcessing] = useState(false);
  const [couponCode, setCouponCode] = useState('');
  const [appliedCoupon, setAppliedCoupon] = useState(null);
  const [couponError, setCouponError] = useState('');

  // Coupon database - now with 10-day campaign flag
  const availableCoupons = {
    'LAUNCH100': { 
      discountPercent: 100, 
      description: '100% OFF - Free 10-Day Ad Campaign',
      isLaunchCampaign: true // Flag for 10-day free campaigns
    },
    'LAUNCH50': { 
      discountPercent: 50, 
      description: '50% OFF Launch Special',
      isLaunchCampaign: false 
    },
    'WELCOME25': { 
      discountPercent: 25, 
      description: '25% OFF Welcome Discount',
      isLaunchCampaign: false 
    },
    'FREETRIAL': { 
      discountPercent: 100, 
      description: '100% OFF - Free 10-Day Trial',
      isLaunchCampaign: true 
    }
  };

  // ... (keep all your existing functions like handlePaymentChange, formatCardNumber, etc.)

  const applyCoupon = () => {
    setCouponError('');
    
    if (!couponCode.trim()) {
      setCouponError('Please enter a coupon code');
      return;
    }

    const coupon = availableCoupons[couponCode.toUpperCase()];
    
    if (coupon) {
      setAppliedCoupon({
        code: couponCode.toUpperCase(),
        ...coupon
      });
      setCouponError('');
    } else {
      setCouponError('Invalid coupon code');
      setAppliedCoupon(null);
    }
  };

  const removeCoupon = () => {
    setAppliedCoupon(null);
    setCouponCode('');
    setCouponError('');
  };

  // Calculate totals
  const baseAmount = orderData.duration || 0;
  const discountAmount = appliedCoupon 
    ? (baseAmount * appliedCoupon.discountPercent) / 100 
    : 0;
  const finalAmount = Math.max(0, baseAmount - discountAmount);

  const handlePaymentSubmit = async (e) => {
    e.preventDefault();
    setIsProcessing(true);

    try {
      await new Promise(resolve => setTimeout(resolve, 2000));
      
      // Calculate campaign duration - 10 days for launch campaigns, otherwise use selected duration
      const campaignDuration = appliedCoupon?.isLaunchCampaign ? 10 : orderData.duration;
      
      // Calculate end date based on campaign type
      const startDate = new Date();
      const endDate = new Date();
      endDate.setDate(startDate.getDate() + campaignDuration);

      // Navigate to success page with updated order details
      navigate('/success', { 
        state: {
          ...orderData,
          duration: campaignDuration, // Override duration for free campaigns
          orderId: `CLK-${Date.now()}`,
          paymentDate: new Date().toISOString(),
          couponUsed: appliedCoupon,
          finalAmount: finalAmount,
          discountAmount: discountAmount,
          campaignStartDate: startDate.toISOString(),
          campaignEndDate: endDate.toISOString(),
          isFreeCampaign: appliedCoupon?.isLaunchCampaign || false
        }
      });
    } catch (error) {
      alert('Payment failed. Please try again.');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="checkout-container">
      <div className="checkout-header">
        <h1>💳 Complete Your Payment</h1>
        <p>Secure payment processed via Stripe</p>
      </div>

      <div className="checkout-content">
        {/* Order Summary */}
        <div className="order-summary">
          <h3>📋 Order Details</h3>
          <div className="summary-details">
            <div className="summary-item">
              <span>Business:</span>
              <strong>{orderData.businessName}</strong>
            </div>
            <div className="summary-item">
              <span>Square:</span>
              <strong>#{orderData.squareNumber} (Page {orderData.pageNumber})</strong>
            </div>
            
            {/* Show different duration based on coupon type */}
            <div className="summary-item">
              <span>Duration:</span>
              <strong>
                {appliedCoupon?.isLaunchCampaign ? '10 days' : `${orderData.duration} days`}
                {appliedCoupon?.isLaunchCampaign && ' 🎁 FREE'}
              </strong>
            </div>
            
            <div className="summary-item">
              <span>Daily Rate:</span>
              <strong>£1.00/day</strong>
            </div>
            
            {/* Coupon Display */}
            {appliedCoupon && (
              <div className="summary-item discount">
                <span>Discount ({appliedCoupon.discountPercent}% OFF):</span>
                <strong>-£{discountAmount}.00</strong>
              </div>
            )}
            
            <div className="summary-item total">
              <span>Total Amount:</span>
              <strong>£{finalAmount}.00</strong>
            </div>

            {/* Free Campaign Notice */}
            {appliedCoupon?.isLaunchCampaign && (
              <div className="campaign-notice">
                🎉 <strong>Free 10-Day Launch Campaign!</strong><br/>
                Your ad will run for 10 days completely free!
              </div>
            )}
          </div>

          {orderData.logoPreview && (
            <div className="logo-review">
              <h4>Your Logo:</h4>
              <img src={orderData.logoPreview} alt="Business logo" />
            </div>
          )}
        </div>

        {/* Payment Form with Coupon Section */}
        <form className="payment-form" onSubmit={handlePaymentSubmit}>
          <div className="form-section">
            <h3>💳 Payment Information</h3>
            
            {/* Coupon Section */}
            <div className="coupon-section-integrated">
              <h4>🎁 Launch Promo Code</h4>
              <div className="coupon-input-group">
                <input
                  type="text"
                  placeholder="Enter launch code (e.g., LAUNCH100)"
                  value={couponCode}
                  onChange={(e) => setCouponCode(e.target.value)}
                  disabled={!!appliedCoupon}
                />
                {!appliedCoupon ? (
                  <button type="button" className="btn-coupon" onClick={applyCoupon}>
                    Apply
                  </button>
                ) : (
                  <button type="button" className="btn-coupon-remove" onClick={removeCoupon}>
                    Remove
                  </button>
                )}
              </div>
              {couponError && <div className="coupon-error">{couponError}</div>}
              {appliedCoupon && (
                <div className="coupon-success">
                  ✅ {appliedCoupon.description}
                  {appliedCoupon.isLaunchCampaign && ' - 10 days free!'}
                </div>
              )}
              
              {/* Promo Code Hints */}
              <div className="coupon-hints">
                <small>
                  <strong>Launch Codes:</strong> LAUNCH100, FREETRIAL (10 days free) • 
                  <strong> Discount Codes:</strong> LAUNCH50, WELCOME25
                </small>
              </div>
            </div>

            {/* Payment Details - Only show if not free campaign */}
            {finalAmount > 0 ? (
              <>
                <div className="form-group">
                  <label htmlFor="cardName">Name on Card *</label>
                  <input
                    type="text"
                    id="cardName"
                    name="cardName"
                    value={paymentData.cardName}
                    onChange={handlePaymentChange}
                    placeholder="John Smith"
                    required
                    autoComplete="cc-name"
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="cardNumber">Card Number *</label>
                  <input
                    type="text"
                    id="cardNumber"
                    name="cardNumber"
                    value={paymentData.cardNumber}
                    onChange={handleCardNumberChange}
                    placeholder="1234 5678 9012 3456"
                    maxLength="19"
                    required
                    autoComplete="cc-number"
                  />
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label htmlFor="expiryDate">Expiry Date *</label>
                    <input
                      type="text"
                      id="expiryDate"
                      name="expiryDate"
                      value={paymentData.expiryDate}
                      onChange={handleExpiryChange}
                      placeholder="MM/YY"
                      maxLength="5"
                      required
                      autoComplete="cc-exp"
                    />
                  </div>

                  <div className="form-group">
                    <label htmlFor="cvv">CVV *</label>
                    <input
                      type="text"
                      id="cvv"
                      name="cvv"
                      value={paymentData.cvv}
                      onChange={handlePaymentChange}
                      placeholder="123"
                      maxLength="4"
                      required
                      autoComplete="cc-csc"
                    />
                  </div>
                </div>

                <div className="form-check">
                  <input
                    type="checkbox"
                    id="saveCard"
                    name="saveCard"
                    checked={paymentData.saveCard}
                    onChange={handlePaymentChange}
                  />
                  <label htmlFor="saveCard">Save card for future payments</label>
                </div>
              </>
            ) : (
              <div className="free-campaign-notice">
                <h4>🎉 Free Campaign Activated!</h4>
                <p>No payment required. Your 10-day free advertising campaign will start immediately after confirmation.</p>
              </div>
            )}
          </div>

          {/* Security Notice - Only show for paid campaigns */}
          {finalAmount > 0 && (
            <div className="security-notice">
              <div className="lock-icon">🔒</div>
              <div>
                <strong>Your payment is secure</strong>
                <p>All transactions are encrypted and secure. We never store your CVV.</p>
              </div>
            </div>
          )}

          <div className="payment-actions">
            <button 
              type="button" 
              className="btn-secondary" 
              onClick={() => navigate(-1)}
              disabled={isProcessing}
            >
              ← Back to Details
            </button>
            <button 
              type="submit" 
              className="btn-primary"
              disabled={isProcessing}
            >
              {isProcessing ? (
                <>
                  <div className="spinner"></div>
                  Processing...
                </>
              ) : finalAmount === 0 ? (
                `🎉 Start Free 10-Day Campaign`
              ) : (
                `Pay £${finalAmount}.00 Now`
              )}
            </button>
          </div>
        </form>
      </div>

      {/* Payment Icons - Only show for paid campaigns */}
      {finalAmount > 0 && (
        <div className="payment-methods">
          <p>We accept:</p>
          <div className="payment-icons">
            <i className="fab fa-cc-visa"></i>
            <i className="fab fa-cc-mastercard"></i>
            <i className="fab fa-cc-amex"></i>
            <i className="fab fa-cc-discover"></i>
            <i className="fab fa-cc-stripe"></i>
          </div>
        </div>
      )}
    </div>
  );
};

export default Checkout;
